#include<bits/stdc++.h>
using namespace std;
int n=5,m=5,a[11][11],flag2=0;

int main(){
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            bool flag=1;
            for(int k=1;k<=n;k++){
                if(a[i][j]>a[k][j]){
                    flag=0;
                    break;
                }
            }
            for(int k=1;k<=m;k++){
                if(a[i][j]<a[i][k]){
                    flag=0;
                    break;
                }
            }
            if(flag){
                flag2=1;
                cout<<i<<" "<<j<<' '<<a[i][j]<<"\n";
            }
        }
    }
    if(!flag2){
        cout<<"not found";
    }
}
